import subprocess

def convertDocument(inputFile, outputFile, outputFormat):
    if not inputFile.endswith('.soffice') and not outputFile.endswith('.soffice'):
        print("Running LibreOffice in headless mode...")
        command = f'sooffice --headless --convert-to {outputFormat} "{inputFile}"'
        try:
            subprocess.run(command, shell=True, check=True)
        except subprocess.CalledProcessError as e:
            print(f"Conversion failed: {e}")
    else:
        print("Input file or output file already contains .soffice extension. Skipping conversion...")

# Example usage
